from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a single fluent sentence that summarizes all provided triples."""
    if not triples:
        return ""
    # Group triples by their subject while preserving order of first appearance
    subject_order = []
    grouped = {}
    for triple in triples:
        subj = triple.subject
        if subj not in grouped:
            grouped[subj] = []
            subject_order.append(subj)
        grouped[subj].append(triple)

    # Helper to turn a predicate‑object pair into a natural phrase
    def phrase(triple: Triple) -> str:
        p, o = triple.predicate, triple.object
        # Mapping of predicates to readable expressions
        if p == "location":
            return f"is located in {o}"
        if p == "country":
            return f"is in {o}"
        if p == "leader":
            return f"is led by {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "demonym":
            return f"has demonym {o}"
        if p == "floorCount":
            return f"has {o} floors"
        if p == "height":
            return f"is {o} metres tall"
        if p == "cost":
            return f"costs {o}"
        if p == "architect":
            return f"was designed by {o}"
        if p == "owner":
            return f"is owned by {o}"
        if p == "formerName":
            return f"was formerly known as {o}"
        if p == "buildingType":
            return f"is a {o}"
        if p == "isPartOf":
            return f"is part of {o}"
        if p == "address":
            return f"is located at {o}"
        if p == "inaugurationDate":
            return f"was inaugurated on {o}"
        if p == "buildingStartDate":
            return f"construction started in {o}"
        if p == "completionDate":
            return f"was completed in {o}"
        if p == "floorArea":
            return f"covers {o} square metres"
        if p == "website":
            return f"has website {o}"
        # Default fallback
        return f"{p.replace('_', ' ')} {o}"

    # Build a clause for each subject
    clauses = []
    for subj in subject_order:
        phrases = [phrase(t) for t in grouped[subj]]
        if not phrases:
            continue
        if len(phrases) == 1:
            clause = f"{subj} {phrases[0]}"
        else:
            body = ", ".join(phrases[:-1]) + f", and {phrases[-1]}"
            clause = f"{subj} {body}"
        clauses.append(clause)

    # Combine clauses into a single sentence
    sentence = "; ".join(clauses) + "."
    return sentence

# EVOLVE-BLOCK-END

